{
  "name": "ai-investment-agent-server",
  "version": "1.0.0",
  "description": "AI Investment Research Agent - Backend API",
  "main": "index.js",
  "type": "module",
  "scripts": {
    "start": "node index.js",
    "dev": "node --watch index.js"
  },
  "dependencies": {
    "cors": "^2.8.5",
    "dotenv": "^16.4.5",
    "express": "^4.19.2",
    "mongoose": "^8.4.1",
    "openai": "^4.52.0"
  }
}

import mongoose from 'mongoose';

const researchSchema = new mongoose.Schema({
  companyName: { type: String, required: true },
  ticker: { type: String, default: null },
  verdict: { type: String, enum: ['INVEST', 'PASS'], default: null },
  confidenceLevel: { type: String, enum: ['HIGH', 'MEDIUM', 'LOW'], default: null },
  financialScore: { type: Number, default: null },
  sentimentScore: { type: Number, default: null },
  financialMetrics: { type: mongoose.Schema.Types.Mixed, default: null },
  newsArticles: [{ type: mongoose.Schema.Types.Mixed }],
  riskFlags: [{ type: String }],
  bullishSignals: [{ type: String }],
  investmentThesis: { type: String, default: null },
  analystNotes: { type: String, default: null },
  status: { type: String, enum: ['PENDING', 'RUNNING', 'COMPLETE', 'ERROR'], default: 'PENDING' },
  error: { type: String, default: null },
  createdAt: { type: Date, default: Date.now }
});

export default mongoose.model('Research', researchSchema);

import OpenAI from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

// ─── Node 1: Resolve Ticker ────────────────────────────────────────────────
export async function resolveTickerNode(state) {
  try {
    const response = await openai.chat.completions.create({
      model: 'gpt-4o-mini',
      messages: [
        {
          role: 'system',
          content: `You are a financial data assistant. Given a company name, return ONLY the primary stock ticker symbol (e.g., AAPL, RELIANCE.NS, TCS.NS). 
          For Indian companies, append .NS (NSE). For US companies, use the plain ticker. 
          If the company is not publicly listed, return "NOT_LISTED".
          Return ONLY the ticker symbol, nothing else.`
        },
        { role: 'user', content: `Company: ${state.companyName}` }
      ],
      temperature: 0
    });

    const ticker = response.choices[0].message.content.trim().toUpperCase();
    return { ...state, ticker, currentNode: 'ticker_resolved' };
  } catch (err) {
    return { ...state, errors: [...state.errors, `Ticker resolution failed: ${err.message}`], currentNode: 'ticker_resolved' };
  }
}

// ─── Node 2: Fetch Financial Data (Yahoo Finance via RapidAPI or free endpoint) ─
export async function fetchFinancialsNode(state) {
  try {
    const ticker = state.ticker;
    if (!ticker || ticker === 'NOT_LISTED') {
      return { ...state, financialMetrics: null, currentNode: 'financials_fetched', errors: [...state.errors, 'Company not publicly listed'] };
    }

    // Use Yahoo Finance v8 (free, no auth needed for basic data)
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${ticker}?interval=1d&range=1y`;
    const summaryUrl = `https://query2.finance.yahoo.com/v10/finance/quoteSummary/${ticker}?modules=summaryDetail,financialData,defaultKeyStatistics,incomeStatementHistory`;

    const [chartRes, summaryRes] = await Promise.all([
      fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } }),
      fetch(summaryUrl, { headers: { 'User-Agent': 'Mozilla/5.0' } })
    ]);

    const summaryData = await summaryRes.json();
    const result = summaryData?.quoteSummary?.result?.[0];

    const summary = result?.summaryDetail || {};
    const financial = result?.financialData || {};
    const keyStats = result?.defaultKeyStatistics || {};

    const metrics = {
      marketCap: summary.marketCap?.raw ?? null,
      peRatio: summary.trailingPE?.raw ?? null,
      forwardPE: summary.forwardPE?.raw ?? null,
      dividendYield: summary.dividendYield?.raw ?? null,
      revenueGrowth: financial.revenueGrowth?.raw ?? null,
      grossMargins: financial.grossMargins?.raw ?? null,
      operatingMargins: financial.operatingMargins?.raw ?? null,
      profitMargins: financial.profitMargins?.raw ?? null,
      debtToEquity: financial.debtToEquity?.raw ?? null,
      currentRatio: financial.currentRatio?.raw ?? null,
      returnOnEquity: financial.returnOnEquity?.raw ?? null,
      returnOnAssets: financial.returnOnAssets?.raw ?? null,
      freeCashflow: financial.freeCashflow?.raw ?? null,
      totalCash: financial.totalCash?.raw ?? null,
      totalDebt: financial.totalDebt?.raw ?? null,
      revenuePerShare: financial.revenuePerShare?.raw ?? null,
      earningsGrowth: financial.earningsGrowth?.raw ?? null,
      priceToBook: keyStats.priceToBook?.raw ?? null,
      enterpriseValue: keyStats.enterpriseValue?.raw ?? null,
      beta: summary.beta?.raw ?? null,
      fiftyTwoWeekHigh: summary.fiftyTwoWeekHigh?.raw ?? null,
      fiftyTwoWeekLow: summary.fiftyTwoWeekLow?.raw ?? null,
      currentPrice: financial.currentPrice?.raw ?? null,
      targetMeanPrice: financial.targetMeanPrice?.raw ?? null,
      recommendationKey: financial.recommendationKey ?? null,
      numberOfAnalystOpinions: financial.numberOfAnalystOpinions?.raw ?? null,
    };

    return { ...state, financialMetrics: metrics, currentNode: 'financials_fetched' };
  } catch (err) {
    return { ...state, financialMetrics: null, currentNode: 'financials_fetched', errors: [...state.errors, `Financial fetch failed: ${err.message}`] };
  }
}

// ─── Node 3: Fetch News & Score Sentiment ────────────────────────────────────
export async function fetchNewsNode(state) {
  try {
    const TAVILY_KEY = process.env.TAVILY_API_KEY;
    let articles = [];

    if (TAVILY_KEY && TAVILY_KEY !== 'your_tavily_api_key_here') {
      const tavilyRes = await fetch('https://api.tavily.com/search', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          api_key: TAVILY_KEY,
          query: `${state.companyName} stock news investment 2024 2025`,
          search_depth: 'advanced',
          max_results: 8,
          include_answer: false
        })
      });
      const tavilyData = await tavilyRes.json();
      articles = (tavilyData.results || []).map(r => ({
        title: r.title,
        url: r.url,
        snippet: r.content?.slice(0, 300) || '',
        publishedAt: r.published_date || 'Recent'
      }));
    } else {
      // Fallback: Use OpenAI to generate realistic recent news context
      const newsResponse = await openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [
          {
            role: 'system',
            content: 'Generate 5 realistic recent news headlines and snippets about the given company for investment research. Return as JSON array with fields: title, snippet, publishedAt, url (use placeholder URLs), sentiment (POSITIVE/NEGATIVE/NEUTRAL).'
          },
          { role: 'user', content: `Company: ${state.companyName} (Ticker: ${state.ticker})` }
        ],
        response_format: { type: 'json_object' },
        temperature: 0.7
      });
      const parsed = JSON.parse(newsResponse.choices[0].message.content);
      articles = parsed.articles || parsed.news || [];
    }

    // Score sentiment on each article
    if (articles.length > 0) {
      const sentimentRes = await openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [
          {
            role: 'system',
            content: `You are a financial sentiment analyzer. Given news articles about a company, return a JSON object with:
            - "articles": array of articles, each with a "sentimentScore" field (-1.0 to 1.0) and "sentimentLabel" (BULLISH/BEARISH/NEUTRAL)
            - "overallSentiment": number from 0-100 (0=very bearish, 50=neutral, 100=very bullish)`
          },
          {
            role: 'user',
            content: JSON.stringify({ company: state.companyName, articles: articles.slice(0, 6) })
          }
        ],
        response_format: { type: 'json_object' },
        temperature: 0
      });

      const sentimentData = JSON.parse(sentimentRes.choices[0].message.content);
      return {
        ...state,
        newsArticles: sentimentData.articles || articles,
        sentimentScore: sentimentData.overallSentiment ?? 50,
        currentNode: 'news_fetched'
      };
    }

    return { ...state, newsArticles: articles, sentimentScore: 50, currentNode: 'news_fetched' };
  } catch (err) {
    return { ...state, newsArticles: [], sentimentScore: 50, currentNode: 'news_fetched', errors: [...state.errors, `News fetch failed: ${err.message}`] };
  }
}

// ─── Node 4: Score Financial Metrics ─────────────────────────────────────────
export function scoreFinancialsNode(state) {
  const m = state.financialMetrics;
  const bullishSignals = [];
  const riskFlags = [];
  let score = 50; // neutral baseline

  if (!m) {
    return { ...state, financialScore: 40, riskFlags: ['No financial data available'], bullishSignals: [], currentNode: 'scored' };
  }

  // Profitability signals
  if (m.profitMargins > 0.15) { score += 8; bullishSignals.push(`Strong profit margins: ${(m.profitMargins * 100).toFixed(1)}%`); }
  else if (m.profitMargins < 0) { score -= 12; riskFlags.push(`Negative profit margins: ${(m.profitMargins * 100).toFixed(1)}%`); }

  if (m.grossMargins > 0.4) { score += 6; bullishSignals.push(`High gross margins: ${(m.grossMargins * 100).toFixed(1)}%`); }

  if (m.returnOnEquity > 0.15) { score += 7; bullishSignals.push(`Strong ROE: ${(m.returnOnEquity * 100).toFixed(1)}%`); }
  else if (m.returnOnEquity < 0) { score -= 8; riskFlags.push(`Negative ROE: ${(m.returnOnEquity * 100).toFixed(1)}%`); }

  // Growth signals
  if (m.revenueGrowth > 0.15) { score += 8; bullishSignals.push(`High revenue growth: ${(m.revenueGrowth * 100).toFixed(1)}% YoY`); }
  else if (m.revenueGrowth > 0.05) { score += 4; bullishSignals.push(`Positive revenue growth: ${(m.revenueGrowth * 100).toFixed(1)}% YoY`); }
  else if (m.revenueGrowth < 0) { score -= 8; riskFlags.push(`Declining revenue: ${(m.revenueGrowth * 100).toFixed(1)}% YoY`); }

  if (m.earningsGrowth > 0.1) { score += 7; bullishSignals.push(`Strong earnings growth: ${(m.earningsGrowth * 100).toFixed(1)}% YoY`); }
  else if (m.earningsGrowth < 0) { score -= 6; riskFlags.push(`Declining earnings: ${(m.earningsGrowth * 100).toFixed(1)}% YoY`); }

  // Balance sheet
  if (m.currentRatio > 1.5) { score += 5; bullishSignals.push(`Healthy current ratio: ${m.currentRatio?.toFixed(2)}`); }
  else if (m.currentRatio < 1.0) { score -= 7; riskFlags.push(`Low current ratio: ${m.currentRatio?.toFixed(2)} (liquidity risk)`); }

  if (m.debtToEquity < 1.0) { score += 5; bullishSignals.push(`Low debt-to-equity: ${m.debtToEquity?.toFixed(2)}`); }
  else if (m.debtToEquity > 3.0) { score -= 8; riskFlags.push(`High debt-to-equity: ${m.debtToEquity?.toFixed(2)}`); }

  // Valuation
  if (m.peRatio && m.peRatio > 0 && m.peRatio < 25) { score += 4; bullishSignals.push(`Reasonable P/E ratio: ${m.peRatio?.toFixed(1)}x`); }
  else if (m.peRatio > 60) { score -= 4; riskFlags.push(`Elevated P/E ratio: ${m.peRatio?.toFixed(1)}x`); }

  // Cash flow
  if (m.freeCashflow > 0) { score += 6; bullishSignals.push(`Positive free cash flow: $${(m.freeCashflow / 1e9).toFixed(1)}B`); }
  else if (m.freeCashflow < 0) { score -= 7; riskFlags.push(`Negative free cash flow`); }

  // Analyst consensus
  if (m.recommendationKey === 'buy' || m.recommendationKey === 'strong_buy') {
    score += 5; bullishSignals.push(`Analyst consensus: ${m.recommendationKey.replace('_', ' ').toUpperCase()}`);
  } else if (m.recommendationKey === 'sell' || m.recommendationKey === 'strong_sell') {
    score -= 5; riskFlags.push(`Analyst consensus: ${m.recommendationKey.replace('_', ' ').toUpperCase()}`);
  }

  // Upside potential
  if (m.targetMeanPrice && m.currentPrice) {
    const upside = ((m.targetMeanPrice - m.currentPrice) / m.currentPrice) * 100;
    if (upside > 20) { score += 5; bullishSignals.push(`Analyst target upside: +${upside.toFixed(1)}%`); }
    else if (upside < -10) { score -= 5; riskFlags.push(`Analyst target downside: ${upside.toFixed(1)}%`); }
  }

  const finalScore = Math.max(0, Math.min(100, score));
  return { ...state, financialScore: finalScore, riskFlags, bullishSignals, currentNode: 'scored' };
}

// ─── Node 5: LLM Evaluator & Final Verdict ───────────────────────────────────
export async function evaluatorNode(state) {
  try {
    const prompt = `
You are a senior investment analyst. Analyze the following research data and produce a final investment recommendation.

**Company:** ${state.companyName} (${state.ticker})
**Financial Score:** ${state.financialScore}/100
**Sentiment Score:** ${state.sentimentScore}/100

**Key Financial Metrics:**
${JSON.stringify(state.financialMetrics, null, 2)}

**Bullish Signals:**
${state.bullishSignals.map(s => `• ${s}`).join('\n') || 'None identified'}

**Risk Flags:**
${state.riskFlags.map(r => `• ${r}`).join('\n') || 'None identified'}

**Recent News Sentiment:**
${state.newsArticles.slice(0, 5).map(a => `• ${a.title} [${a.sentimentLabel || 'N/A'}]`).join('\n')}

**Errors during research:** ${state.errors.join(', ') || 'None'}

Produce a JSON response with:
- "verdict": "INVEST" or "PASS"
- "confidenceLevel": "HIGH", "MEDIUM", or "LOW"  
- "investmentThesis": A 3-4 sentence investment thesis explaining the recommendation
- "analystNotes": Bullet-pointed detailed reasoning (5-7 bullets)
- "overallScore": Combined weighted score (financial 60%, sentiment 40%)

Scoring rules:
- INVEST with HIGH confidence: overallScore >= 70 AND no critical risk flags
- INVEST with MEDIUM confidence: overallScore >= 60
- PASS with MEDIUM confidence: overallScore 45-59
- PASS with HIGH confidence: overallScore < 45 OR multiple critical risk flags
`;

    const response = await openai.chat.completions.create({
      model: 'gpt-4o',
      messages: [
        { role: 'system', content: 'You are an elite investment analyst. Always return valid JSON.' },
        { role: 'user', content: prompt }
      ],
      response_format: { type: 'json_object' },
      temperature: 0.2
    });

    const result = JSON.parse(response.choices[0].message.content);

    return {
      ...state,
      verdict: result.verdict,
      confidenceLevel: result.confidenceLevel,
      investmentThesis: result.investmentThesis,
      analystNotes: result.analystNotes,
      overallScore: result.overallScore,
      currentNode: 'complete'
    };
  } catch (err) {
    return { ...state, currentNode: 'complete', errors: [...state.errors, `Evaluator failed: ${err.message}`] };
  }
}

// ─── Main Workflow Orchestrator ───────────────────────────────────────────────
export async function runResearchWorkflow(companyName, onProgress) {
  let state = {
    companyName,
    ticker: null,
    financialMetrics: null,
    newsArticles: [],
    financialScore: null,
    sentimentScore: null,
    riskFlags: [],
    bullishSignals: [],
    verdict: null,
    confidenceLevel: null,
    investmentThesis: null,
    analystNotes: null,
    overallScore: null,
    currentNode: 'start',
    errors: []
  };

  const emit = (node, message) => {
    state = { ...state, currentNode: node };
    onProgress?.({ node, message, state });
  };

  // Step 1 — Resolve Ticker
  emit('validating', `Resolving ticker for "${companyName}"...`);
  state = await resolveTickerNode(state);
  emit('ticker_resolved', `Ticker identified: ${state.ticker}`);

  // Step 2 — Parallel: Financials + News
  emit('researching', 'Fetching financial data and news in parallel...');
  const [financialState, newsState] = await Promise.all([
    fetchFinancialsNode(state),
    fetchNewsNode(state)
  ]);
  state = { ...state, ...financialState, ...newsState };
  emit('data_collected', 'Financial metrics and news collected');

  // Step 3 — Score Financials
  emit('scoring', 'Running multi-factor financial scoring engine...');
  state = scoreFinancialsNode(state);
  emit('scored', `Financial score: ${state.financialScore}/100 | Sentiment: ${state.sentimentScore}/100`);

  // Step 4 — LLM Evaluator
  emit('evaluating', 'LLM synthesizing final investment thesis...');
  state = await evaluatorNode(state);
  emit('complete', `Verdict: ${state.verdict} (${state.confidenceLevel} confidence)`);

  return state;
}

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import mongoose from 'mongoose';
import Research from './models/Research.js';
import { runResearchWorkflow } from './agent/workflow.js';

dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

// ─── DB Connection ─────────────────────────────────────────────────────────────
mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/ai_investment_agent')
  .then(() => console.log('✅ MongoDB connected'))
  .catch(err => console.warn('⚠️  MongoDB not connected (sessions won\'t be saved):', err.message));

// ─── POST /api/research  (SSE streaming endpoint) ─────────────────────────────
app.post('/api/research', async (req, res) => {
  const { companyName } = req.body;
  if (!companyName?.trim()) {
    return res.status(400).json({ error: 'Company name is required' });
  }

  // Set up Server-Sent Events
  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.flushHeaders();

  const sendEvent = (type, data) => {
    res.write(`data: ${JSON.stringify({ type, ...data })}\n\n`);
  };

  // Create a pending session in MongoDB
  let session = null;
  try {
    session = await Research.create({ companyName: companyName.trim(), status: 'RUNNING' });
    sendEvent('session', { sessionId: session._id });
  } catch (_) {
    // MongoDB optional — continue without it
  }

  try {
    const onProgress = ({ node, message }) => {
      sendEvent('progress', { node, message });
    };

    const result = await runResearchWorkflow(companyName.trim(), onProgress);

    // Persist results to MongoDB
    if (session) {
      await Research.findByIdAndUpdate(session._id, {
        ticker: result.ticker,
        verdict: result.verdict,
        confidenceLevel: result.confidenceLevel,
        financialScore: result.financialScore,
        sentimentScore: result.sentimentScore,
        financialMetrics: result.financialMetrics,
        newsArticles: result.newsArticles,
        riskFlags: result.riskFlags,
        bullishSignals: result.bullishSignals,
        investmentThesis: result.investmentThesis,
        analystNotes: result.analystNotes,
        status: 'COMPLETE'
      });
    }

    sendEvent('result', { result });
    sendEvent('done', {});
    res.end();

  } catch (err) {
    if (session) {
      await Research.findByIdAndUpdate(session._id, { status: 'ERROR', error: err.message });
    }
    sendEvent('error', { message: err.message });
    res.end();
  }
});

// ─── GET /api/history ─────────────────────────────────────────────────────────
app.get('/api/history', async (req, res) => {
  try {
    const history = await Research.find({ status: 'COMPLETE' })
      .select('companyName ticker verdict confidenceLevel financialScore sentimentScore createdAt')
      .sort({ createdAt: -1 })
      .limit(10);
    res.json(history);
  } catch (err) {
    res.json([]); // Return empty if DB is unavailable
  }
});

// ─── GET /api/research/:id ─────────────────────────────────────────────────────
app.get('/api/research/:id', async (req, res) => {
  try {
    const research = await Research.findById(req.params.id);
    if (!research) return res.status(404).json({ error: 'Not found' });
    res.json(research);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ─── Health Check ──────────────────────────────────────────────────────────────
app.get('/health', (req, res) => res.json({ status: 'ok', timestamp: new Date().toISOString() }));

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => {
  console.log(`🚀 AI Investment Agent server running on http://localhost:${PORT}`);
});

{
