import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<React.StrictMode><App /></React.StrictMode>);

import React, { useState, useEffect, useCallback } from 'react';
import SearchBar from './components/SearchBar';
import AgentProgress from './components/AgentProgress';
import VerdictCard from './components/VerdictCard';
import FinancialsTable from './components/FinancialsTable';
import SentimentPanel from './components/SentimentPanel';
import SignalsList from './components/SignalsList';
import HistorySidebar from './components/HistorySidebar';
import ThesisPanel from './components/ThesisPanel';

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL || 'http://localhost:5000';

export default function App() {
  const [phase, setPhase] = useState('idle'); // idle | loading | result | error
  const [progressSteps, setProgressSteps] = useState([]);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [history, setHistory] = useState([]);
  const [activeTab, setActiveTab] = useState('thesis');
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const fetchHistory = useCallback(async () => {
    try {
      const res = await fetch(`${BACKEND_URL}/api/history`);
      const data = await res.json();
      setHistory(data);
    } catch (_) {}
  }, []);

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  const handleSearch = async (companyName) => {
    setPhase('loading');
    setProgressSteps([]);
    setResult(null);
    setError(null);
    setActiveTab('thesis');

    const NODE_LABELS = {
      validating:     'Resolving ticker symbol',
      ticker_resolved:'Ticker identified',
      researching:    'Fetching data in parallel',
      data_collected: 'Data collection complete',
      scoring:        'Running financial scoring',
      scored:         'Scores computed',
      evaluating:     'LLM synthesizing verdict',
      complete:       'Analysis complete',
    };

    try {
      const response = await fetch(`${BACKEND_URL}/api/research`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ companyName }),
      });

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop();

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          try {
            const event = JSON.parse(line.slice(6));
            if (event.type === 'progress') {
              setProgressSteps(prev => {
                const exists = prev.find(s => s.node === event.node);
                if (exists) return prev.map(s => s.node === event.node ? { ...s, message: event.message, status: 'done' } : s);
                return [...prev, { node: event.node, label: NODE_LABELS[event.node] || event.node, message: event.message, status: 'active' }];
              });
            } else if (event.type === 'result') {
              setResult(event.result);
              setPhase('result');
              setProgressSteps(prev => prev.map(s => ({ ...s, status: 'done' })));
              fetchHistory();
            } else if (event.type === 'error') {
              setError(event.message);
              setPhase('error');
            }
          } catch (_) {}
        }
      }
    } catch (err) {
      setError(err.message);
      setPhase('error');
    }
  };

  return (
    <div className="min-h-screen bg-dark-900 text-white font-sans">
      {/* ── Background Gradient ── */}
