import React from 'react';

const STEP_ORDER = [
  'validating', 'ticker_resolved',
  'researching', 'data_collected',
  'scoring', 'scored',
  'evaluating', 'complete'
];

const STEP_META = {
  validating:     { label: 'Input Validation',     icon: '🔍', color: 'accent-cyan' },
  ticker_resolved:{ label: 'Ticker Resolved',       icon: '🏷️',  color: 'accent-cyan' },
  researching:    { label: 'Parallel Research',     icon: '📡', color: 'accent-blue' },
  data_collected: { label: 'Data Collected',        icon: '📦', color: 'accent-blue' },
  scoring:        { label: 'Financial Scoring',     icon: '⚙️',  color: 'accent-purple' },
  scored:         { label: 'Scores Computed',       icon: '🧮', color: 'accent-purple' },
  evaluating:     { label: 'LLM Evaluation',        icon: '🤖', color: 'accent-amber' },
  complete:       { label: 'Analysis Complete',     icon: '✅', color: 'accent-green' },
};

export default function AgentProgress({ steps, isLoading }) {
  const seen = new Set(steps.map(s => s.node));
  const activeNode = steps.findLast(s => s.status === 'active')?.node || steps[steps.length - 1]?.node;

  return (
    <div className="bg-dark-800 border border-white/5 rounded-2xl p-5">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-sm font-semibold text-white/60 uppercase tracking-widest">Agent Progress</h3>
        {isLoading && (
          <span className="flex items-center gap-1.5 text-xs text-accent-blue">
            <span className="w-1.5 h-1.5 rounded-full bg-accent-blue animate-ping" />
            Running
          </span>
        )}
      </div>

      <div className="space-y-2">
        {STEP_ORDER.map((stepKey, index) => {
          const step = steps.find(s => s.node === stepKey);
          const meta = STEP_META[stepKey];
          const isDone = step?.status === 'done';
          const isActive = step && step.status === 'active';
          const isPending = !step;

          return (
            <div
              key={stepKey}
              className={`flex items-start gap-3 p-3 rounded-xl transition-all duration-300 ${
                isDone   ? 'bg-white/3 opacity-80' :
                isActive ? 'bg-accent-blue/10 border border-accent-blue/20' :
                'opacity-30'
              }`}
            >
              {/* Icon / Status */}
              <div className="w-7 h-7 flex items-center justify-center rounded-lg flex-shrink-0 mt-0.5">
                {isDone   ? <span className="text-accent-green text-sm">✓</span> :
                 isActive ? <svg className="animate-spin w-4 h-4 text-accent-blue" viewBox="0 0 24 24" fill="none"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/></svg> :
                 <span className="text-white/30 text-sm">{meta.icon}</span>}
              </div>

              {/* Content */}
              <div className="flex-1 min-w-0">
                <div className={`text-sm font-medium ${isDone ? 'text-white/70' : isActive ? 'text-white' : 'text-white/30'}`}>
                  {meta.label}
                </div>
                {(isDone || isActive) && step?.message && (
                  <div className="text-xs text-white/40 mt-0.5 truncate font-mono">{step.message}</div>
                )}
              </div>

              {/* Step number */}
              <span className="text-xs text-white/20 font-mono">{String(index + 1).padStart(2, '0')}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

