export default function VerdictCard({ result }) {
  const isInvest = result.verdict === 'INVEST';
  const confidenceColors = { HIGH: '#10d98a', MEDIUM: '#f59e0b', LOW: '#ff4d6d' };

  const formatMarketCap = (val) => {
    if (!val) return 'N/A';
    if (val >= 1e12) return `$${(val / 1e12).toFixed(2)}T`;
    if (val >= 1e9)  return `$${(val / 1e9).toFixed(1)}B`;
    if (val >= 1e6)  return `$${(val / 1e6).toFixed(1)}M`;
    return `$${val}`;
  };

  return (
    <div className={`relative overflow-hidden rounded-2xl border ${
      isInvest
        ? 'border-accent-green/30 shadow-glow-green bg-gradient-to-br from-accent-green/10 to-dark-800'
        : 'border-accent-red/30 shadow-glow-red bg-gradient-to-br from-accent-red/10 to-dark-800'
    }`}>
      {/* Decorative blur */}
      <div className={`absolute top-0 right-0 w-64 h-64 rounded-full blur-3xl opacity-10 ${isInvest ? 'bg-accent-green' : 'bg-accent-red'}`} />

      <div className="relative p-6">
        <div className="flex flex-col md:flex-row md:items-start gap-6">
          {/* Verdict badge */}
          <div className="flex-shrink-0">
            <div className={`inline-flex items-center gap-3 px-6 py-4 rounded-xl border ${
              isInvest
                ? 'bg-accent-green/20 border-accent-green/40 text-accent-green'
                : 'bg-accent-red/20 border-accent-red/40 text-accent-red'
            }`}>
              <span className="text-3xl">{isInvest ? '✅' : '❌'}</span>
              <div>
                <div className="text-3xl font-black tracking-widest">{result.verdict}</div>
                <div className="text-sm opacity-70">
                  {result.confidenceLevel} confidence
                </div>
              </div>
            </div>

            {/* Ticker info */}
            <div className="mt-3 flex gap-2 flex-wrap">
              {result.ticker && (
                <span className="px-3 py-1 bg-dark-700 rounded-lg text-xs font-mono text-white/60 border border-white/5">
                  {result.ticker}
                </span>
              )}
              {result.financialMetrics?.recommendationKey && (
                <span className="px-3 py-1 bg-dark-700 rounded-lg text-xs text-white/60 border border-white/5 capitalize">
                  Analysts: {result.financialMetrics.recommendationKey.replace('_', ' ')}
                </span>
              )}
              {result.financialMetrics?.marketCap && (
                <span className="px-3 py-1 bg-dark-700 rounded-lg text-xs text-white/60 border border-white/5">
                  Mkt Cap: {formatMarketCap(result.financialMetrics.marketCap)}
                </span>
              )}
            </div>
          </div>

          {/* Scores */}
          <div className="flex-1 space-y-4">
            <h3 className="text-xs uppercase tracking-widest text-white/40 font-semibold">Analysis Scores</h3>
            <ScoreBar label="Financial Score"  score={result.financialScore}  color="#4f8ef7" />
            <ScoreBar label="News Sentiment"   score={result.sentimentScore}  color="#8b5cf6" />
            {result.overallScore != null && (
              <ScoreBar label="Overall Score"  score={result.overallScore}    color={isInvest ? '#10d98a' : '#ff4d6d'} />
            )}
          </div>
        </div>

        {/* Errors */}
        {result.errors?.length > 0 && (
          <div className="mt-4 p-3 bg-accent-amber/10 border border-accent-amber/20 rounded-lg text-xs text-accent-amber">
            ⚠️ Note: {result.errors.join(' | ')}
          </div>
        )}
      </div>
    </div>
  );
}

