  { key: 'peRatio',           label: 'P/E Ratio (TTM)',     format: v => v != null ? `${v.toFixed(1)}x` : null },
  { key: 'forwardPE',         label: 'Forward P/E',         format: v => v != null ? `${v.toFixed(1)}x` : null },
  { key: 'priceToBook',       label: 'Price / Book',        format: v => v != null ? `${v.toFixed(2)}x` : null },
  { key: 'revenueGrowth',     label: 'Revenue Growth YoY',  format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'earningsGrowth',    label: 'Earnings Growth YoY', format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'grossMargins',      label: 'Gross Margin',        format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'operatingMargins',  label: 'Operating Margin',    format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'profitMargins',     label: 'Net Profit Margin',   format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'returnOnEquity',    label: 'Return on Equity',    format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'returnOnAssets',    label: 'Return on Assets',    format: v => v != null ? `${(v*100).toFixed(1)}%` : null, positive: true },
  { key: 'currentRatio',      label: 'Current Ratio',       format: v => v != null ? v.toFixed(2) : null },
  { key: 'debtToEquity',      label: 'Debt / Equity',       format: v => v != null ? v.toFixed(2) : null },
  { key: 'freeCashflow',      label: 'Free Cash Flow',      format: v => v != null ? (v >= 1e9 ? `$${(v/1e9).toFixed(1)}B` : `$${(v/1e6).toFixed(0)}M`) : null, positive: true },
  { key: 'beta',              label: 'Beta',                format: v => v != null ? v.toFixed(2) : null },
  { key: 'dividendYield',     label: 'Dividend Yield',      format: v => v != null ? `${(v*100).toFixed(2)}%` : null },
  { key: 'targetMeanPrice',   label: 'Analyst Target',      format: v => v != null ? `$${v.toFixed(2)}` : null },
  { key: 'numberOfAnalystOpinions', label: 'Analyst Count', format: v => v != null ? v : null },
  { key: 'fiftyTwoWeekHigh',  label: '52-Week High',        format: v => v != null ? `$${v.toFixed(2)}` : null },
  { key: 'fiftyTwoWeekLow',   label: '52-Week Low',         format: v => v != null ? `$${v.toFixed(2)}` : null },
];

export default function FinancialsTable({ metrics, ticker }) {
  if (!metrics) {
    return (
      <div className="bg-dark-800 border border-white/5 rounded-2xl p-8 text-center">
        <div className="text-4xl mb-3">📊</div>
        <p className="text-white/40">No financial data available for this company.</p>
      </div>
    );
  }

  const upside = metrics.targetMeanPrice && metrics.currentPrice
    ? ((metrics.targetMeanPrice - metrics.currentPrice) / metrics.currentPrice * 100)
    : null;

  return (
    <div className="bg-dark-800 border border-white/5 rounded-2xl overflow-hidden">
      <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between">
        <h3 className="text-sm font-semibold text-white/50 uppercase tracking-widest">Financial Metrics</h3>
        {ticker && <span className="font-mono text-accent-blue text-sm">{ticker}</span>}
      </div>

      {/* Upside banner */}
      {upside != null && (
        <div className={`px-6 py-3 text-sm border-b border-white/5 ${upside > 0 ? 'bg-accent-green/10 text-accent-green' : 'bg-accent-red/10 text-accent-red'}`}>
          Analyst Price Target Upside: {upside > 0 ? '+' : ''}{upside.toFixed(1)}%
          {metrics.targetMeanPrice && ` (Target: $${metrics.targetMeanPrice.toFixed(2)})`}
        </div>
      )}

      <div className="divide-y divide-white/5">
        {METRICS.map(({ key, label, format, positive }) => {
          const raw = metrics[key];
          if (raw == null) return null;
          const display = format(raw);
          if (!display) return null;

          const isPositive = positive && raw > 0;
          const isNegative = positive && raw < 0;

          return (
            <div key={key} className="flex items-center justify-between px-6 py-3 hover:bg-white/2 transition-colors">
              <span className="text-sm text-white/60">{label}</span>
              <span className={`font-mono text-sm font-medium ${
                isPositive ? 'text-accent-green' :
                isNegative ? 'text-accent-red' :
                'text-white/90'
              }`}>
                {display}
              </span>
            </div>
          );
        }).filter(Boolean)}
      </div>

      <div className="px-6 py-3 border-t border-white/5 text-xs text-white/20">
        Data sourced from Yahoo Finance — for informational purposes only. Not financial advice.
      </div>
    </div>
  );
}

import React from 'react';

const SENTIMENT_COLOR = { BULLISH: '#10d98a', BEARISH: '#ff4d6d', POSITIVE: '#10d98a', NEGATIVE: '#ff4d6d', NEUTRAL: '#f59e0b' };
const SENTIMENT_BG = { BULLISH: 'bg-accent-green/10 border-accent-green/30 text-accent-green', BEARISH: 'bg-accent-red/10 border-accent-red/30 text-accent-red', POSITIVE: 'bg-accent-green/10 border-accent-green/30 text-accent-green', NEGATIVE: 'bg-accent-red/10 border-accent-red/30 text-accent-red', NEUTRAL: 'bg-accent-amber/10 border-accent-amber/30 text-accent-amber' };

export default function SentimentPanel({ articles, score }) {
  const label = score >= 65 ? 'BULLISH' : score >= 45 ? 'NEUTRAL' : 'BEARISH';
  const labelColor = SENTIMENT_COLOR[label];

  return (
    <div className="space-y-4">
      {/* Overall Score */}
      <div className="bg-dark-800 border border-white/5 rounded-2xl p-6">
        <h3 className="text-sm font-semibold text-white/50 uppercase tracking-widest mb-4">Overall News Sentiment</h3>
