              <circle cx="50" cy="50" r="40" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="10" />
              <circle
                cx="50" cy="50" r="40"
                fill="none"
                stroke={labelColor}
                strokeWidth="10"
                strokeDasharray={`${(score ?? 0) * 2.51} 251`}
                strokeLinecap="round"
              />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center">
              <span className="text-lg font-bold" style={{ color: labelColor }}>{score?.toFixed(0) ?? '--'}</span>
            </div>
          </div>
          <div>
            <div className="text-2xl font-bold" style={{ color: labelColor }}>{label}</div>
            <div className="text-white/40 text-sm mt-1">Based on {articles?.length ?? 0} recent articles</div>
          </div>
        </div>
      </div>

