{
  "name": "ai-investment-agent-client",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.3.1",
    "vite": "^5.4.0"
  }
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
  server: {
    port: 3000,
    proxy: {
      '/api': {
        target: 'http://localhost:5000',
        changeOrigin: true,
      }
    }
  }
})

import React, { useState, useEffect, useCallback } from 'react'
import SearchBar from './components/SearchBar'
import AgentProgress from './components/AgentProgress'
import VerdictCard from './components/VerdictCard'
import FinancialsTable from './components/FinancialsTable'
import SentimentPanel from './components/SentimentPanel'
import SignalsList from './components/SignalsList'
import HistorySidebar from './components/HistorySidebar'
import ThesisPanel from './components/ThesisPanel'

const BACKEND_URL = import.meta.env.VITE_BACKEND_URL || ''

export default function App() {
  const [phase, setPhase] = useState('idle')
  const [progressSteps, setProgressSteps] = useState([])
  const [result, setResult] = useState(null)
  const [error, setError] = useState(null)
  const [history, setHistory] = useState([])
  const [activeTab, setActiveTab] = useState('thesis')
  const [sidebarOpen, setSidebarOpen] = useState(false)

  const NODE_LABELS = {
    validating:     'Resolving Ticker Symbol',
    ticker_resolved:'Ticker Identified',
    researching:    'Fetching Data in Parallel',
    data_collected: 'Data Collection Complete',
    scoring:        'Running Financial Scoring',
    scored:         'Scores Computed',
    evaluating:     'LLM Synthesizing Verdict',
    complete:       'Analysis Complete',
  }

  const fetchHistory = useCallback(async () => {
    try {
      const res = await fetch(`${BACKEND_URL}/api/history`)
      if (!res.ok) return
      const data = await res.json()
      setHistory(data)
    } catch (_) {}
  }, [])

  useEffect(() => { fetchHistory() }, [fetchHistory])

  const handleSearch = async (companyName) => {
    setPhase('loading')
    setProgressSteps([])
    setResult(null)
    setError(null)
    setActiveTab('thesis')

    try {
      const response = await fetch(`${BACKEND_URL}/api/research`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ companyName }),
      })

      if (!response.ok) {
        const err = await response.json()
        throw new Error(err.error || 'Server error')
      }

      const reader = response.body.getReader()
      const decoder = new TextDecoder()
      let buffer = ''

      while (true) {
        const { done, value } = await reader.read()
        if (done) break
        buffer += decoder.decode(value, { stream: true })
        const lines = buffer.split('\n')
        buffer = lines.pop()

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue
          try {
            const event = JSON.parse(line.slice(6))
            if (event.type === 'progress') {
              setProgressSteps(prev => {
                const exists = prev.find(s => s.node === event.node)
                if (exists) {
                  return prev.map(s =>
                    s.node === event.node ? { ...s, message: event.message, status: 'done' } : s
                  )
                }
                return [...prev, {
                  node: event.node,
                  label: NODE_LABELS[event.node] || event.node,
                  message: event.message,
                  status: 'active'
                }]
              })
            } else if (event.type === 'result') {
              setResult(event.result)
              setPhase('result')
              setProgressSteps(prev => prev.map(s => ({ ...s, status: 'done' })))
              fetchHistory()
            } else if (event.type === 'error') {
              setError(event.message)
              setPhase('error')
            }
          } catch (_) {}
        }
      }
    } catch (err) {
      setError(err.message)
      setPhase('error')
    }
  }

  const QUICK_SEARCHES = ['Apple Inc.', 'Reliance Industries', 'Tesla', 'Infosys', 'HDFC Bank']

  return (
    <div className="min-h-screen bg-[#0a0a14] text-white" style={{ fontFamily: 'Inter, sans-serif' }}>
      {/* Background glows */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden">
        <div className="absolute top-0 left-1/4 w-96 h-96 rounded-full blur-3xl" style={{ background: 'rgba(139,92,246,0.06)' }} />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 rounded-full blur-3xl" style={{ background: 'rgba(79,142,247,0.06)' }} />
      </div>

      <div className="relative flex min-h-screen">
        {/* Sidebar */}
        <HistorySidebar history={history} isOpen={sidebarOpen} onToggle={() => setSidebarOpen(o => !o)} />

        {/* Main */}
        <main className="flex-1 flex flex-col min-h-screen overflow-hidden">
          {/* Header */}
          <header style={{ background: 'rgba(15,15,31,0.8)', borderBottom: '1px solid rgba(255,255,255,0.05)', backdropFilter: 'blur(12px)' }} className="px-6 py-4 sticky top-0 z-10">
            <div className="max-w-4xl mx-auto flex items-center justify-between">
              <div className="flex items-center gap-3">
                <button onClick={() => setSidebarOpen(o => !o)} className="p-2 rounded-lg hover:bg-white/5 transition-colors md:hidden">☰</button>
                <div>
                  <div className="flex items-center gap-2">
                    <span className="text-xl">🔬</span>
                    <h1 className="text-lg font-bold" style={{ background: 'linear-gradient(135deg,#4f8ef7,#8b5cf6)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                      AI Investment Research Agent
                    </h1>
                  </div>
                  <p className="text-xs mt-0.5" style={{ color: 'rgba(255,255,255,0.35)' }}>InsideIIM × Altuni AI Labs</p>
                </div>
              </div>
              <div className="hidden md:flex items-center gap-2 text-xs" style={{ color: 'rgba(255,255,255,0.3)' }}>
                <span className="w-2 h-2 rounded-full bg-emerald-400 inline-block animate-pulse" />
                GPT-4o + Yahoo Finance
              </div>
            </div>
          </header>

          {/* Content */}
          <div className="flex-1 max-w-4xl mx-auto w-full px-4 py-8 space-y-5">
            <SearchBar onSearch={handleSearch} disabled={phase === 'loading'} />

            {(phase === 'loading' || (phase === 'result' && progressSteps.length > 0)) && (
              <AgentProgress steps={progressSteps} isLoading={phase === 'loading'} />
            )}

            {phase === 'error' && (
              <div className="rounded-2xl p-5 border" style={{ background: 'rgba(255,77,109,0.08)', borderColor: 'rgba(255,77,109,0.3)' }}>
                <p className="font-semibold" style={{ color: '#ff4d6d' }}>⚠️ Research Failed</p>
                <p className="text-sm mt-1" style={{ color: 'rgba(255,255,255,0.55)' }}>{error}</p>
                <p className="text-xs mt-2" style={{ color: 'rgba(255,255,255,0.35)' }}>
                  Make sure your <code className="px-1 py-0.5 rounded" style={{ background: 'rgba(255,255,255,0.08)' }}>OPENAI_API_KEY</code> is set in <code className="px-1 py-0.5 rounded" style={{ background: 'rgba(255,255,255,0.08)' }}>server/.env</code>
                </p>
              </div>
            )}

            {phase === 'result' && result && (
              <div className="space-y-4">
                <VerdictCard result={result} />

                {/* Tabs */}
                <div className="flex gap-1 p-1 rounded-xl border" style={{ background: 'rgba(15,15,31,0.8)', borderColor: 'rgba(255,255,255,0.05)' }}>
                  {[
                    { id: 'thesis',     label: '📋 Thesis' },
                    { id: 'financials', label: '📊 Financials' },
                    { id: 'sentiment',  label: '📰 Sentiment' },
                    { id: 'signals',    label: '🚦 Signals' },
                  ].map(tab => (
                    <button
                      key={tab.id}
                      id={`tab-${tab.id}`}
                      onClick={() => setActiveTab(tab.id)}
                      className="flex-1 py-2 px-3 rounded-lg text-sm font-medium transition-all"
                      style={activeTab === tab.id
                        ? { background: 'rgba(79,142,247,0.15)', color: '#4f8ef7', border: '1px solid rgba(79,142,247,0.3)' }
                        : { color: 'rgba(255,255,255,0.4)' }
                      }
                    >
                      {tab.label}
                    </button>
                  ))}
                </div>

                <div>
                  {activeTab === 'thesis'     && <ThesisPanel result={result} />}
                  {activeTab === 'financials' && <FinancialsTable metrics={result.financialMetrics} ticker={result.ticker} />}
                  {activeTab === 'sentiment'  && <SentimentPanel articles={result.newsArticles} score={result.sentimentScore} />}
                  {activeTab === 'signals'    && <SignalsList bullish={result.bullishSignals} risks={result.riskFlags} />}
                </div>
              </div>
            )}

            {phase === 'idle' && (
              <div className="text-center py-16">
                <div className="text-6xl mb-4">📈</div>
                <h2 className="text-2xl font-bold mb-2" style={{ color: 'rgba(255,255,255,0.85)' }}>Research Any Public Company</h2>
                <p className="text-sm max-w-md mx-auto" style={{ color: 'rgba(255,255,255,0.4)' }}>
                  Enter a company name. The agent fetches live financial data, scans recent news, and delivers an AI-powered INVEST or PASS verdict.
                </p>
                <div className="mt-8 flex flex-wrap justify-center gap-2">
                  {QUICK_SEARCHES.map(c => (
                    <button
                      key={c}
                      onClick={() => handleSearch(c)}
                      className="px-4 py-2 rounded-full text-sm transition-all"
                      style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', color: 'rgba(255,255,255,0.55)' }}
                      onMouseEnter={e => { e.target.style.borderColor = 'rgba(79,142,247,0.4)'; e.target.style.color = 'rgba(255,255,255,0.85)' }}
                      onMouseLeave={e => { e.target.style.borderColor = 'rgba(255,255,255,0.08)'; e.target.style.color = 'rgba(255,255,255,0.55)' }}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  )
}

import React, { useState } from 'react'

export default function SearchBar({ onSearch, disabled }) {
  const [value, setValue] = useState('')

  const handleSubmit = (e) => {
    e.preventDefault()
    if (value.trim() && !disabled) onSearch(value.trim())
  }

  return (
    <form onSubmit={handleSubmit}>
      <div style={{ position: 'relative' }}>
        {/* Glow border */}
        <div style={{
          position: 'absolute', inset: '-1px', borderRadius: '16px',
          background: 'linear-gradient(135deg, #4f8ef7, #8b5cf6)',
          opacity: disabled ? 0.15 : 0.3, filter: 'blur(4px)', transition: 'opacity 0.3s'
        }} />
        <div style={{
          position: 'relative', display: 'flex', alignItems: 'center',
          background: '#0f0f1f', border: '1px solid rgba(255,255,255,0.08)',
          borderRadius: '16px', overflow: 'hidden'
        }}>
          <span style={{ paddingLeft: '20px', fontSize: '20px', color: 'rgba(255,255,255,0.25)' }}>🔍</span>
          <input
            id="company-search-input"
            type="text"
            value={value}
            onChange={e => setValue(e.target.value)}
            placeholder="Enter a company name (e.g. Apple Inc., Reliance Industries, Tesla...)"
            disabled={disabled}
            autoComplete="off"
            style={{
              flex: 1, background: 'transparent', border: 'none', outline: 'none',
              padding: '20px 16px', color: 'white', fontSize: '16px',
              fontFamily: 'Inter, sans-serif',
              opacity: disabled ? 0.5 : 1
            }}
          />
          <button
            id="search-submit-btn"
            type="submit"
            disabled={disabled || !value.trim()}
            style={{
              margin: '8px', padding: '12px 24px',
              background: disabled || !value.trim() ? 'rgba(79,142,247,0.3)' : 'linear-gradient(135deg,#4f8ef7,#8b5cf6)',
              border: 'none', borderRadius: '12px', color: 'white',
              fontWeight: '600', fontSize: '14px', cursor: disabled || !value.trim() ? 'not-allowed' : 'pointer',
              display: 'flex', alignItems: 'center', gap: '8px', whiteSpace: 'nowrap',
              transition: 'all 0.2s', fontFamily: 'Inter, sans-serif'
            }}
          >
            {disabled ? (
              <>
                <svg style={{ width: 16, height: 16, animation: 'spin 1s linear infinite' }} viewBox="0 0 24 24" fill="none">
                  <circle style={{ opacity: 0.25 }} cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                  <path style={{ opacity: 0.75 }} fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                </svg>
                Analyzing...
              </>
            ) : 'Analyze →'}
          </button>
        </div>
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </form>
  )
}

import React from 'react'

const STEP_ORDER = [
  { key: 'validating',      label: 'Input Validation',     icon: '🔍' },
  { key: 'ticker_resolved', label: 'Ticker Resolved',       icon: '🏷️'  },
  { key: 'researching',     label: 'Parallel Research',     icon: '📡' },
  { key: 'data_collected',  label: 'Data Collected',        icon: '📦' },
  { key: 'scoring',         label: 'Financial Scoring',     icon: '⚙️'  },
  { key: 'scored',          label: 'Scores Computed',       icon: '🧮' },
  { key: 'evaluating',      label: 'LLM Evaluation',        icon: '🤖' },
  { key: 'complete',        label: 'Analysis Complete',     icon: '✅' },
]

export default function AgentProgress({ steps, isLoading }) {
  return (
    <div style={{ background: '#0f0f1f', border: '1px solid rgba(255,255,255,0.06)', borderRadius: '16px', padding: '20px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
        <span style={{ fontSize: '11px', fontWeight: 600, color: 'rgba(255,255,255,0.4)', letterSpacing: '0.1em', textTransform: 'uppercase' }}>
          Agent Progress
        </span>
        {isLoading && (
          <span style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '12px', color: '#4f8ef7' }}>
            <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#4f8ef7', display: 'inline-block', animation: 'ping 1s ease-in-out infinite' }} />
            Running
          </span>
        )}
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
        {STEP_ORDER.map(({ key, label, icon }, index) => {
          const step = steps.find(s => s.node === key)
          const isDone   = step?.status === 'done'
          const isActive = step?.status === 'active'

          return (
            <div
              key={key}
              style={{
                display: 'flex', alignItems: 'center', gap: '12px',
                padding: '10px 12px', borderRadius: '10px',
                background: isDone ? 'rgba(255,255,255,0.02)' : isActive ? 'rgba(79,142,247,0.08)' : 'transparent',
                border: isActive ? '1px solid rgba(79,142,247,0.2)' : '1px solid transparent',
                opacity: !step ? 0.3 : 1,
                transition: 'all 0.3s'
              }}
            >
              <div style={{ width: 24, height: 24, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                {isDone
                  ? <span style={{ color: '#10d98a', fontSize: 14, fontWeight: 700 }}>✓</span>
                  : isActive
                  ? <svg style={{ width: 16, height: 16, color: '#4f8ef7', animation: 'spin 1s linear infinite' }} viewBox="0 0 24 24" fill="none">
                      <circle style={{ opacity: 0.25 }} cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                      <path style={{ opacity: 0.75 }} fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                    </svg>
                  : <span style={{ fontSize: 13, opacity: 0.4 }}>{icon}</span>
                }
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 13, fontWeight: 500, color: isDone ? 'rgba(255,255,255,0.65)' : isActive ? 'white' : 'rgba(255,255,255,0.3)' }}>
                  {label}
                </div>
                {step?.message && (
                  <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)', marginTop: 2, fontFamily: 'JetBrains Mono, monospace', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {step.message}
                  </div>
                )}
              </div>
              <span style={{ fontSize: 10, color: 'rgba(255,255,255,0.15)', fontFamily: 'monospace' }}>
                {String(index + 1).padStart(2, '0')}
              </span>
            </div>
          )
        })}
      </div>
      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes ping { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.5;transform:scale(1.3)} }
      `}</style>
    </div>
  )
}

import React from 'react'

function ScoreBar({ label, score, color }) {
  return (
    <div style={{ marginBottom: 12 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
        <span style={{ fontSize: 13, color: 'rgba(255,255,255,0.55)' }}>{label}</span>
        <span style={{ fontSize: 13, fontFamily: 'JetBrains Mono, monospace', fontWeight: 600, color }}>{score?.toFixed(0) ?? '--'}/100</span>
      </div>
      <div style={{ height: 6, background: 'rgba(255,255,255,0.05)', borderRadius: 999, overflow: 'hidden' }}>
        <div style={{
          height: '100%', borderRadius: 999, width: `${score ?? 0}%`,
          background: `linear-gradient(90deg, ${color}66, ${color})`,
          transition: 'width 1s ease'
        }} />
      </div>
    </div>
  )
}

export default function VerdictCard({ result }) {
  const isInvest = result.verdict === 'INVEST'
  const glow     = isInvest ? 'rgba(16,217,138,0.18)' : 'rgba(255,77,109,0.18)'
  const border   = isInvest ? 'rgba(16,217,138,0.3)' : 'rgba(255,77,109,0.3)'
  const color    = isInvest ? '#10d98a' : '#ff4d6d'

  const fmt = (v) => {
    if (!v) return 'N/A'
    if (v >= 1e12) return `$${(v/1e12).toFixed(2)}T`
    if (v >= 1e9)  return `$${(v/1e9).toFixed(1)}B`
    if (v >= 1e6)  return `$${(v/1e6).toFixed(0)}M`
    return `$${v}`
  }

  return (
    <div style={{
      position: 'relative', overflow: 'hidden', borderRadius: '20px',
      border: `1px solid ${border}`,
      background: `linear-gradient(135deg, ${glow}, #0f0f1f)`,
      boxShadow: `0 0 40px ${glow}`
    }}>
      {/* Decorative blur */}
      <div style={{
        position: 'absolute', top: -40, right: -40, width: 180, height: 180,
        borderRadius: '50%', filter: 'blur(40px)', opacity: 0.15,
        background: color, pointerEvents: 'none'
      }} />

      <div style={{ position: 'relative', padding: '24px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
          {/* Top row */}
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 20, alignItems: 'flex-start' }}>
            {/* Badge */}
            <div style={{
              display: 'inline-flex', alignItems: 'center', gap: 14, padding: '16px 24px',
              borderRadius: '14px', border: `1px solid ${border}`,
              background: isInvest ? 'rgba(16,217,138,0.12)' : 'rgba(255,77,109,0.12)'
            }}>
              <span style={{ fontSize: 32 }}>{isInvest ? '✅' : '❌'}</span>
              <div>
                <div style={{ fontSize: 28, fontWeight: 900, letterSpacing: '0.12em', color }}>{result.verdict}</div>
                <div style={{ fontSize: 12, color, opacity: 0.7 }}>{result.confidenceLevel} confidence</div>
              </div>
            </div>

            {/* Scores */}
            <div style={{ flex: 1, minWidth: 220 }}>
              <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)', letterSpacing: '0.08em', marginBottom: 12, textTransform: 'uppercase' }}>
                Analysis Scores
              </div>
              <ScoreBar label="Financial Score" score={result.financialScore} color="#4f8ef7" />
              <ScoreBar label="News Sentiment"  score={result.sentimentScore} color="#8b5cf6" />
              {result.overallScore != null && (
                <ScoreBar label="Overall Score" score={result.overallScore} color={color} />
              )}
            </div>
          </div>

          {/* Tags row */}
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
            {result.ticker && (
              <span style={{ padding: '4px 12px', borderRadius: 8, background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', fontSize: 12, fontFamily: 'monospace', color: 'rgba(255,255,255,0.6)' }}>
                {result.ticker}
              </span>
            )}
            {result.financialMetrics?.recommendationKey && (
              <span style={{ padding: '4px 12px', borderRadius: 8, background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', fontSize: 12, color: 'rgba(255,255,255,0.6)', textTransform: 'capitalize' }}>
                Analysts: {result.financialMetrics.recommendationKey.replace('_', ' ')}
              </span>
            )}
            {result.financialMetrics?.marketCap && (
              <span style={{ padding: '4px 12px', borderRadius: 8, background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', fontSize: 12, color: 'rgba(255,255,255,0.6)' }}>
                Mkt Cap: {fmt(result.financialMetrics.marketCap)}
              </span>
