import React from 'react'

export default function ThesisPanel({ result }) {
  const bullets = result.analystNotes
    ? result.analystNotes.split('\n').filter(l => l.trim()).map(l => l.replace(/^[-•*▸]\s*/, ''))
    : []

  const card = { background: '#0f0f1f', border: '1px solid rgba(255,255,255,0.06)', borderRadius: '16px', padding: '24px', marginBottom: 16 }

  return (
    <div>
      <div style={card}>
        <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.4)', letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 14 }}>
          Investment Thesis
        </div>
        <blockquote style={{
          borderLeft: '2px solid rgba(79,142,247,0.5)', paddingLeft: 16,
          fontSize: 15, lineHeight: 1.7, color: 'rgba(255,255,255,0.8)', margin: 0
        }}>
          {result.investmentThesis || 'No thesis generated.'}
        </blockquote>
      </div>

      {bullets.length > 0 && (
        <div style={card}>
          <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.4)', letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 16 }}>
            Analyst Notes
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {bullets.map((b, i) => (
              <div key={i} style={{ display: 'flex', gap: 12, alignItems: 'flex-start' }}>
                <span style={{ color: '#4f8ef7', flexShrink: 0, marginTop: 2, fontSize: 13 }}>▸</span>
                <span style={{ fontSize: 14, color: 'rgba(255,255,255,0.75)', lineHeight: 1.6 }}>{b}</span>
