import React from 'react'

const SL_STYLE = {
  BULLISH:  { bg: 'rgba(16,217,138,0.1)',  border: 'rgba(16,217,138,0.3)',  color: '#10d98a' },
  BEARISH:  { bg: 'rgba(255,77,109,0.1)',  border: 'rgba(255,77,109,0.3)',  color: '#ff4d6d' },
  POSITIVE: { bg: 'rgba(16,217,138,0.1)',  border: 'rgba(16,217,138,0.3)',  color: '#10d98a' },
  NEGATIVE: { bg: 'rgba(255,77,109,0.1)',  border: 'rgba(255,77,109,0.3)',  color: '#ff4d6d' },
  NEUTRAL:  { bg: 'rgba(245,158,11,0.1)',  border: 'rgba(245,158,11,0.3)',  color: '#f59e0b' },
}

export default function SentimentPanel({ articles, score }) {
  const label = (score ?? 50) >= 65 ? 'BULLISH' : (score ?? 50) >= 45 ? 'NEUTRAL' : 'BEARISH'
  const lStyle = SL_STYLE[label]
  const circum = 2 * Math.PI * 38
  const dash   = (score ?? 0) / 100 * circum

  return (
    <div>
      {/* Score gauge */}
      <div style={{ background: '#0f0f1f', border: '1px solid rgba(255,255,255,0.06)', borderRadius: 16, padding: 24, marginBottom: 16 }}>
        <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.4)', letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 16 }}>
          Overall News Sentiment
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
          {/* SVG gauge */}
          <div style={{ position: 'relative', width: 90, height: 90, flexShrink: 0 }}>
            <svg viewBox="0 0 100 100" style={{ width: '100%', height: '100%', transform: 'rotate(-90deg)' }}>
              <circle cx="50" cy="50" r="38" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="10" />
              <circle cx="50" cy="50" r="38" fill="none" stroke={lStyle.color} strokeWidth="10"
                strokeDasharray={`${dash} ${circum}`} strokeLinecap="round" style={{ transition: 'stroke-dasharray 1s ease' }} />
            </svg>
            <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <span style={{ fontSize: 17, fontWeight: 700, color: lStyle.color }}>{score?.toFixed(0) ?? '--'}</span>
            </div>
          </div>
          <div>
            <div style={{ fontSize: 22, fontWeight: 700, color: lStyle.color }}>{label}</div>
            <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.4)', marginTop: 4 }}>
              Based on {articles?.length ?? 0} recent articles
            </div>
          </div>
        </div>
      </div>

      {/* Articles */}
      {articles?.length > 0 && (
        <div style={{ background: '#0f0f1f', border: '1px solid rgba(255,255,255,0.06)', borderRadius: 16, overflow: 'hidden' }}>
          <div style={{ padding: '14px 24px', borderBottom: '1px solid rgba(255,255,255,0.05)', fontSize: 11, color: 'rgba(255,255,255,0.4)', letterSpacing: '0.1em', textTransform: 'uppercase' }}>
            Recent Headlines
          </div>
          {articles.map((a, i) => {
            const sl = (a.sentimentLabel || 'NEUTRAL').toUpperCase()
            const s  = SL_STYLE[sl] || SL_STYLE.NEUTRAL
            return (
              <div key={i} style={{ padding: '16px 24px', borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                <div style={{ display: 'flex', gap: 12, marginBottom: 6, alignItems: 'flex-start' }}>
                  <div style={{ flex: 1, fontSize: 13, fontWeight: 500, color: 'rgba(255,255,255,0.82)', lineHeight: 1.5 }}>
                    {a.url && a.url !== '#'
                      ? <a href={a.url} target="_blank" rel="noopener noreferrer" style={{ color: 'inherit', textDecoration: 'none' }}
                           onMouseEnter={e => e.target.style.color='#4f8ef7'} onMouseLeave={e => e.target.style.color='rgba(255,255,255,0.82)'}>{a.title}</a>
                      : a.title}
                  </div>
                  <span style={{ padding: '3px 8px', borderRadius: 6, border: `1px solid ${s.border}`, background: s.bg, color: s.color, fontSize: 11, fontWeight: 600, flexShrink: 0 }}>
                    {sl}
                  </span>
                </div>
                {a.snippet && <p style={{ fontSize: 12, color: 'rgba(255,255,255,0.38)', lineHeight: 1.5, margin: 0 }}>{a.snippet}</p>}
                {a.publishedAt && <p style={{ fontSize: 11, color: 'rgba(255,255,255,0.22)', margin: '4px 0 0' }}>{a.publishedAt}</p>}
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

import React from 'react'

export default function SignalsList({ bullish = [], risks = [] }) {
  const col = (bg, border, hdr, count, items, icon) => (
    <div style={{ background: '#0f0f1f', border: `1px solid ${border}`, borderRadius: 16, overflow: 'hidden', flex: 1, minWidth: 240 }}>
      <div style={{ padding: '14px 18px', background: bg, borderBottom: `1px solid ${border}`, display: 'flex', alignItems: 'center', gap: 8 }}>
        <span>{icon}</span>
        <span style={{ fontSize: 11, fontWeight: 700, color: hdr, letterSpacing: '0.08em', textTransform: 'uppercase' }}>
          {icon === '✅' ? 'Bullish Signals' : 'Risk Flags'}
        </span>
        <span style={{ marginLeft: 'auto', padding: '2px 8px', borderRadius: 999, background: bg, border: `1px solid ${border}`, fontSize: 11, color: hdr }}>{count}</span>
      </div>
      <div style={{ padding: 12 }}>
        {items.length === 0
          ? <p style={{ textAlign: 'center', color: 'rgba(255,255,255,0.25)', fontSize: 13, padding: '16px 0' }}>None identified</p>
          : items.map((item, i) => (
            <div key={i} style={{ display: 'flex', gap: 10, alignItems: 'flex-start', padding: '10px 12px', borderRadius: 10, background: bg, marginBottom: 6 }}>
              <span style={{ color: hdr, fontSize: 11, flexShrink: 0, marginTop: 3 }}>▸</span>
              <span style={{ fontSize: 13, color: 'rgba(255,255,255,0.78)', lineHeight: 1.5 }}>{item}</span>
            </div>
          ))
        }
      </div>
    </div>
  )

  return (
    <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
      {col('rgba(16,217,138,0.06)', 'rgba(16,217,138,0.2)', '#10d98a', bullish.length, bullish, '✅')}
      {col('rgba(255,77,109,0.06)', 'rgba(255,77,109,0.2)', '#ff4d6d', risks.length, risks, '⚠️')}
    </div>
  )
}

import React from 'react'

const V_COLORS = {
  INVEST: { text: '#10d98a', bg: 'rgba(16,217,138,0.1)', border: 'rgba(16,217,138,0.3)' },
  PASS:   { text: '#ff4d6d', bg: 'rgba(255,77,109,0.1)', border: 'rgba(255,77,109,0.3)' },
}

export default function HistorySidebar({ history, isOpen, onToggle }) {
  const row = (session) => {
    const vc = V_COLORS[session.verdict] || {}
    return (
      <div key={session._id} style={{ padding: '10px 12px', borderRadius: 10, cursor: 'pointer', transition: 'background 0.2s' }}
           onMouseEnter={e => e.currentTarget.style.background='rgba(255,255,255,0.04)'}
           onMouseLeave={e => e.currentTarget.style.background='transparent'}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
          <span style={{ fontSize: 13, fontWeight: 500, color: 'rgba(255,255,255,0.8)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>
            {session.companyName}
          </span>
          {session.verdict && (
            <span style={{ padding: '2px 8px', borderRadius: 6, background: vc.bg, border: `1px solid ${vc.border}`, color: vc.text, fontSize: 11, fontWeight: 600, marginLeft: 8, flexShrink: 0 }}>
              {session.verdict}
            </span>
          )}
        </div>
        <div style={{ display: 'flex', gap: 6, fontSize: 11, color: 'rgba(255,255,255,0.28)' }}>
          {session.ticker && <span style={{ fontFamily: 'monospace' }}>{session.ticker}</span>}
          {session.ticker && <span>·</span>}
          <span>{new Date(session.createdAt).toLocaleDateString()}</span>
        </div>
      </div>
    )
  }

  const inner = (
    <>
      <div style={{ padding: '14px 18px', borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
        <span style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)', letterSpacing: '0.1em', textTransform: 'uppercase' }}>Research History</span>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: 8 }}>
        {history.length === 0
          ? <div style={{ textAlign: 'center', padding: '40px 16px', color: 'rgba(255,255,255,0.2)', fontSize: 13 }}>
              <div style={{ fontSize: 28, marginBottom: 8 }}>🕐</div>No sessions yet
            </div>
          : history.map(row)
        }
      </div>
    </>
  )

  const sidebarStyle = { width: 240, background: '#0a0a18', borderRight: '1px solid rgba(255,255,255,0.05)', display: 'flex', flexDirection: 'column' }

  return (
    <>
      {/* Desktop */}
      <aside style={{ ...sidebarStyle, display: 'none' }} className="md-sidebar">
        {inner}
      </aside>
      <style>{`@media(min-width:768px){.md-sidebar{display:flex!important}}`}</style>

      {/* Mobile overlay */}
      {isOpen && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 50, display: 'flex' }}>
          <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)' }} onClick={onToggle} />
          <aside style={{ ...sidebarStyle, position: 'relative', width: 260 }}>
            <div style={{ padding: '14px 18px', borderBottom: '1px solid rgba(255,255,255,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)', letterSpacing: '0.1em', textTransform: 'uppercase' }}>History</span>
              <button onClick={onToggle} style={{ background: 'none', border: 'none', color: 'rgba(255,255,255,0.4)', fontSize: 18, cursor: 'pointer' }}>✕</button>
            </div>
            <div style={{ flex: 1, overflowY: 'auto', padding: 8 }}>
              {history.length === 0
                ? <div style={{ textAlign: 'center', padding: 24, color: 'rgba(255,255,255,0.2)', fontSize: 13 }}>No sessions yet</div>
                : history.map(row)}
            </div>
          </aside>
        </div>
      )}
    </>
  )
}

