const res = await fetch('http://localhost:5000/api/research', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ companyName: 'Apple Inc' })
});

const reader = res.body.getReader();
const dec = new TextDecoder();
let buf = '';
process.stdout.write('\n--- LIVE TEST: Apple Inc ---\n');
while (true) {
  const { done, value } = await reader.read();
  if (done) break;
  buf += dec.decode(value, { stream: true });
  const lines = buf.split('\n');
  buf = lines.pop();
  for (const line of lines) {
    if (!line.startsWith('data: ')) continue;
    try {
      const e = JSON.parse(line.slice(6));
      if (e.type === 'progress') process.stdout.write(`  [${e.node}] ${e.message}\n`);
      if (e.type === 'result')   {
        const r = e.result;
        process.stdout.write(`\n  VERDICT: ${r.verdict} (${r.confidenceLevel})\n`);
        process.stdout.write(`  Financial Score: ${r.financialScore}/100\n`);
        process.stdout.write(`  Sentiment Score: ${r.sentimentScore}/100\n`);
        process.stdout.write(`  Overall Score:   ${r.overallScore}/100\n`);
        process.stdout.write(`  Ticker: ${r.ticker}\n`);
        process.stdout.write(`  News Articles: ${r.newsArticles?.length}\n`);
        process.stdout.write(`  Bullish Signals: ${r.bullishSignals?.length}\n`);
        process.stdout.write(`  Risk Flags: ${r.riskFlags?.length}\n`);
        process.stdout.write(`\n  Thesis preview: ${r.investmentThesis?.slice(0,120)}...\n`);
      }
    } catch(_) {}
  }
}
process.stdout.write('\n--- TEST COMPLETE ---\n');

