// ─── Node 2: Fetch Financial Metrics (Yahoo Finance — Free, No Auth) ──────────
export async function fetchFinancialsNode(state) {
  try {
    const { ticker } = state;
    if (!ticker) {
      return { ...state, financialMetrics: null, currentNode: 'financials_fetched' };
    }

    const HEADERS = {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      'Accept': 'application/json',
      'Accept-Language': 'en-US,en;q=0.9',
      'Referer': 'https://finance.yahoo.com/',
      'Origin': 'https://finance.yahoo.com',
    };

    // Use Yahoo Finance v11 (more permissive than v10)
    const modules = 'summaryDetail,financialData,defaultKeyStatistics,assetProfile';
    const url = `https://query1.finance.yahoo.com/v11/finance/quoteSummary/${ticker}?modules=${modules}&corsDomain=finance.yahoo.com`;

    const res = await fetch(url, { headers: HEADERS });

    let r = null;
    if (res.ok) {
      const data = await res.json();
      r = data?.quoteSummary?.result?.[0];
    }

    // Fallback: try v10
    if (!r) {
      const res2 = await fetch(
        `https://query2.finance.yahoo.com/v10/finance/quoteSummary/${ticker}?modules=${modules}`,
        { headers: HEADERS }
      );
      if (res2.ok) {
        const data2 = await res2.json();
        r = data2?.quoteSummary?.result?.[0];
      }
    }

    // Second fallback: use the simple quote endpoint
    if (!r) {
      const res3 = await fetch(
        `https://query1.finance.yahoo.com/v8/finance/chart/${ticker}?interval=1d&range=5d`,
        { headers: HEADERS }
      );
      if (res3.ok) {
        const data3 = await res3.json();
        const meta = data3?.chart?.result?.[0]?.meta;
        if (meta) {
          // Build partial metrics from chart meta
          const metrics = {
            currentPrice:  meta.regularMarketPrice      ?? null,
            marketCap:     meta.marketCap               ?? null,
            fiftyTwoWeekHigh: meta.fiftyTwoWeekHigh     ?? null,
            fiftyTwoWeekLow:  meta.fiftyTwoWeekLow      ?? null,
            sector:        null, industry: null, country: null,
          };
          return { ...state, financialMetrics: metrics, currentNode: 'financials_fetched' };
        }
      }
      throw new Error('All Yahoo Finance endpoints blocked or returned no data');
    }

    const sd = r.summaryDetail         || {};
    const fd = r.financialData         || {};
    const ks = r.defaultKeyStatistics  || {};
    const ap = r.assetProfile          || {};

    const metrics = {
      currentPrice:            fd.currentPrice?.raw            ?? sd.regularMarketPrice?.raw ?? null,
      marketCap:               sd.marketCap?.raw               ?? null,
      peRatio:                 sd.trailingPE?.raw              ?? null,
      forwardPE:               sd.forwardPE?.raw               ?? null,
      priceToBook:             ks.priceToBook?.raw             ?? null,
      revenueGrowth:           fd.revenueGrowth?.raw           ?? null,
      earningsGrowth:          fd.earningsGrowth?.raw          ?? null,
      grossMargins:            fd.grossMargins?.raw            ?? null,
      operatingMargins:        fd.operatingMargins?.raw        ?? null,
      profitMargins:           fd.profitMargins?.raw           ?? null,
      returnOnEquity:          fd.returnOnEquity?.raw          ?? null,
      returnOnAssets:          fd.returnOnAssets?.raw          ?? null,
      currentRatio:            fd.currentRatio?.raw            ?? null,
      debtToEquity:            fd.debtToEquity?.raw            ?? null,
      freeCashflow:            fd.freeCashflow?.raw            ?? null,
      totalCash:               fd.totalCash?.raw               ?? null,
      totalDebt:               fd.totalDebt?.raw               ?? null,
      revenuePerShare:         fd.revenuePerShare?.raw         ?? null,
      beta:                    sd.beta?.raw                    ?? null,
      dividendYield:           sd.dividendYield?.raw           ?? null,
      fiftyTwoWeekHigh:        sd.fiftyTwoWeekHigh?.raw        ?? null,
      fiftyTwoWeekLow:         sd.fiftyTwoWeekLow?.raw         ?? null,
      targetMeanPrice:         fd.targetMeanPrice?.raw         ?? null,
      recommendationKey:       fd.recommendationKey            ?? null,
      numberOfAnalystOpinions: fd.numberOfAnalystOpinions?.raw ?? null,
      sector:                  ap.sector                       ?? null,
      industry:                ap.industry                     ?? null,
      country:                 ap.country                      ?? null,
      fullTimeEmployees:       ap.fullTimeEmployees            ?? null,
      website:                 ap.website                      ?? null,
    };

    return { ...state, financialMetrics: metrics, currentNode: 'financials_fetched' };
  } catch (err) {
    return { ...state, financialMetrics: null, currentNode: 'financials_fetched', errors: [...state.errors, `Financial fetch failed: ${err.message}`] };
  }
}

