  }
}

import { useEffect, useRef } from 'react'
import * as THREE from 'three'

// Animated 3D particle network — financial data visualization aesthetic
export default function ThreeBackground() {
  const mountRef = useRef(null)

  useEffect(() => {
    const el = mountRef.current
    if (!el) return

    // ── Scene setup ──────────────────────────────────────────────────────
    const scene    = new THREE.Scene()
    const camera   = new THREE.PerspectiveCamera(60, el.clientWidth / el.clientHeight, 0.1, 1000)
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true })

    renderer.setSize(el.clientWidth, el.clientHeight)
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2))
    renderer.setClearColor(0x000000, 0)
    el.appendChild(renderer.domElement)
    camera.position.z = 80

    // ── Particles ────────────────────────────────────────────────────────
    const PARTICLE_COUNT = 120
    const positions = []
    const velocities = []

    for (let i = 0; i < PARTICLE_COUNT; i++) {
      positions.push(
        (Math.random() - 0.5) * 180,
        (Math.random() - 0.5) * 120,
        (Math.random() - 0.5) * 80
      )
      velocities.push(
        (Math.random() - 0.5) * 0.04,
        (Math.random() - 0.5) * 0.04,
        (Math.random() - 0.5) * 0.02
      )
    }

    const geo = new THREE.BufferGeometry()
    geo.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))

    const mat = new THREE.PointsMaterial({
      color: 0x4f8ef7,
      size: 1.2,
      transparent: true,
      opacity: 0.7,
      sizeAttenuation: true,
    })

    const particles = new THREE.Points(geo, mat)
    scene.add(particles)

    // ── Connection lines ──────────────────────────────────────────────────
    const lineMat = new THREE.LineBasicMaterial({
      color: 0x4f8ef7,
      transparent: true,
      opacity: 0.08,
    })

    // ── Mouse parallax ────────────────────────────────────────────────────
    let mouseX = 0
    let mouseY = 0
    const onMouseMove = (e) => {
      mouseX = (e.clientX / window.innerWidth  - 0.5) * 0.3
      mouseY = (e.clientY / window.innerHeight - 0.5) * 0.3
    }
    window.addEventListener('mousemove', onMouseMove)

    // ── Resize handler ────────────────────────────────────────────────────
    const onResize = () => {
      camera.aspect = el.clientWidth / el.clientHeight
      camera.updateProjectionMatrix()
      renderer.setSize(el.clientWidth, el.clientHeight)
    }
    window.addEventListener('resize', onResize)

    // ── Animation loop ────────────────────────────────────────────────────
    let frameId
    let linesMesh = null

    const animate = () => {
      frameId = requestAnimationFrame(animate)

      const pos = geo.attributes.position.array

      // Update particle positions
      for (let i = 0; i < PARTICLE_COUNT; i++) {
        const ix = i * 3, iy = i * 3 + 1, iz = i * 3 + 2
        pos[ix] += velocities[i * 3]
        pos[iy] += velocities[i * 3 + 1]
        pos[iz] += velocities[i * 3 + 2]

        // Bounce off boundaries
        if (Math.abs(pos[ix]) > 90)  velocities[i * 3]     *= -1
        if (Math.abs(pos[iy]) > 60)  velocities[i * 3 + 1] *= -1
        if (Math.abs(pos[iz]) > 40)  velocities[i * 3 + 2] *= -1
      }
      geo.attributes.position.needsUpdate = true

      // Rebuild connection lines every 3 frames for performance
      if (frameId % 3 === 0) {
        if (linesMesh) { scene.remove(linesMesh); linesMesh.geometry.dispose() }
        const linePositions = []
        const CONNECT_DIST = 28

        for (let i = 0; i < PARTICLE_COUNT; i++) {
          for (let j = i + 1; j < PARTICLE_COUNT; j++) {
            const dx = pos[i*3]   - pos[j*3]
            const dy = pos[i*3+1] - pos[j*3+1]
            const dz = pos[i*3+2] - pos[j*3+2]
            const dist = Math.sqrt(dx*dx + dy*dy + dz*dz)

            if (dist < CONNECT_DIST) {
              linePositions.push(pos[i*3], pos[i*3+1], pos[i*3+2])
              linePositions.push(pos[j*3], pos[j*3+1], pos[j*3+2])
            }
          }
        }

        if (linePositions.length > 0) {
          const lineGeo = new THREE.BufferGeometry()
          lineGeo.setAttribute('position', new THREE.Float32BufferAttribute(linePositions, 3))
          linesMesh = new THREE.LineSegments(lineGeo, lineMat)
          scene.add(linesMesh)
        }
      }

      // Smooth camera follow mouse
      camera.position.x += (mouseX * 12 - camera.position.x) * 0.03
      camera.position.y += (-mouseY * 8  - camera.position.y) * 0.03
      camera.lookAt(scene.position)

      renderer.render(scene, camera)
    }

    animate()

    return () => {
      cancelAnimationFrame(frameId)
      window.removeEventListener('mousemove', onMouseMove)
      window.removeEventListener('resize', onResize)
      renderer.dispose()
      if (el.contains(renderer.domElement)) el.removeChild(renderer.domElement)
    }
  }, [])

  return (
    <div
      ref={mountRef}
      style={{
        position: 'fixed', inset: 0,
        zIndex: 0, pointerEvents: 'none',
        background: 'radial-gradient(ellipse at 30% 20%, #0d1240 0%, #070714 50%, #0a0108 100%)',
      }}
    />
  )
}

import { useRef, useCallback } from 'react'

// Gives any card a smooth 3D tilt effect that follows the mouse
export function useTilt(strength = 12) {
  const ref = useRef(null)

  const onMouseMove = useCallback((e) => {
    const card = ref.current
    if (!card) return

    const rect   = card.getBoundingClientRect()
    const cx     = rect.left + rect.width  / 2
    const cy     = rect.top  + rect.height / 2
    const dx     = (e.clientX - cx) / (rect.width  / 2)
    const dy     = (e.clientY - cy) / (rect.height / 2)
    const rotateX = -dy * strength
    const rotateY =  dx * strength

    card.style.transform = `perspective(800px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale3d(1.02,1.02,1.02)`
  }, [strength])

  const onMouseLeave = useCallback(() => {
    const card = ref.current
    if (!card) return
    card.style.transform = 'perspective(800px) rotateX(0deg) rotateY(0deg) scale3d(1,1,1)'
  }, [])

  return { ref, onMouseMove, onMouseLeave }
}

/* ── Design Tokens ──────────────────────────────────────── */
:root {
  --blue:      #4f8ef7;
  --purple:    #8b5cf6;
  --green:     #10d98a;
  --red:       #ff4d6d;
  --amber:     #f59e0b;
  --bg:        #07071a;
  --surface:   rgba(15, 15, 40, 0.7);
  --border:    rgba(255, 255, 255, 0.07);
  --text:      rgba(255, 255, 255, 0.88);
  --muted:     rgba(255, 255, 255, 0.45);
  --dim:       rgba(255, 255, 255, 0.2);
  --radius:    16px;
  --radius-sm: 10px;
  --font:      'Inter', system-ui, sans-serif;
  --mono:      'JetBrains Mono', monospace;
}

/* ── Reset & Base ───────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
}

/* ── Glass Card ─────────────────────────────────────────── */
.glass {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  transform-style: preserve-3d;
  will-change: transform;
}

.glass:hover {
  box-shadow: 0 24px 60px rgba(0, 0, 0, 0.5);
}

/* ── Gradient Text ──────────────────────────────────────── */
.grad-text {
  background: linear-gradient(135deg, var(--blue), var(--purple));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ── Glow borders ───────────────────────────────────────── */
.glow-green { box-shadow: 0 0 40px rgba(16, 217, 138, 0.2), inset 0 0 40px rgba(16, 217, 138, 0.03); }
.glow-red   { box-shadow: 0 0 40px rgba(255, 77, 109, 0.2), inset 0 0 40px rgba(255, 77, 109, 0.03); }
.glow-blue  { box-shadow: 0 0 30px rgba(79, 142, 247, 0.15); }

/* ── Animated gradient border ───────────────────────────── */
.grad-border {
  position: relative;
}
.grad-border::before {
  content: '';
  position: absolute;
  inset: -1px;
  border-radius: calc(var(--radius) + 1px);
  background: linear-gradient(135deg, var(--blue), var(--purple), var(--blue));
  background-size: 200% 200%;
  animation: gradShift 4s ease infinite;
  z-index: -1;
  opacity: 0;
  transition: opacity 0.3s;
}
.grad-border:hover::before { opacity: 1; }

/* ── Animations ─────────────────────────────────────────── */
@keyframes gradShift {
  0%   { background-position: 0% 50%; }
  50%  { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

@keyframes ping {
  0%,100% { opacity: 1; transform: scale(1); }
  50%      { opacity: 0.5; transform: scale(1.4); }
}

@keyframes shimmer {
  from { background-position: -200% 0; }
  to   { background-position:  200% 0; }
}

@keyframes float {
  0%,100% { transform: translateY(0px); }
  50%      { transform: translateY(-6px); }
}

.anim-fade-up   { animation: fadeUp 0.5s ease both; }
.anim-spin      { animation: spin 1s linear infinite; }
.anim-ping      { animation: ping 1.2s ease-in-out infinite; }
.anim-float     { animation: float 3s ease-in-out infinite; }

/* ── Score bar ──────────────────────────────────────────── */
.score-bar-track {
  height: 6px;
  background: rgba(255,255,255,0.06);
  border-radius: 999px;
  overflow: hidden;
}
.score-bar-fill {
  height: 100%;
  border-radius: 999px;
  transition: width 1.2s cubic-bezier(0.22, 1, 0.36, 1);
}

/* ── Scrollbar ──────────────────────────────────────────── */
::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 999px; }
::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }

/* ── Input ──────────────────────────────────────────────── */
input { -webkit-tap-highlight-color: transparent; }
input::placeholder { color: rgba(255,255,255,0.25); }

/* ── Utility ────────────────────────────────────────────── */
.mono { font-family: var(--mono); }
.truncate { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

import React, { useState, useEffect, useCallback } from 'react'
import ThreeBackground from './three/Background'
import SearchBar       from './components/SearchBar'
import AgentProgress   from './components/AgentProgress'
import VerdictCard     from './components/VerdictCard'
import FinancialsTable from './components/FinancialsTable'
import SentimentPanel  from './components/SentimentPanel'
import SignalsList     from './components/SignalsList'
import ThesisPanel     from './components/ThesisPanel'
import HistorySidebar  from './components/HistorySidebar'

const NODE_LABELS = {
  validating:     'Resolving Ticker Symbol',
  ticker_resolved:'Ticker Identified',
  researching:    'Fetching Data in Parallel',
  data_collected: 'Data Collection Complete',
  scoring:        'Financial Scoring Engine',
  scored:         'Scores Computed',
  evaluating:     'Generating Investment Thesis',
  complete:       'Analysis Complete',
}

const QUICK_PICKS = ['Apple Inc.', 'Tesla', 'Reliance Industries', 'Infosys', 'HDFC Bank']

export default function App() {
  const [phase,         setPhase]         = useState('idle')     // idle | loading | result | error
  const [steps,         setSteps]         = useState([])
  const [result,        setResult]        = useState(null)
  const [errorMsg,      setErrorMsg]      = useState(null)
  const [history,       setHistory]       = useState([])
  const [activeTab,     setActiveTab]     = useState('thesis')
  const [sidebarOpen,   setSidebarOpen]   = useState(false)

  // Load research history from the backend
  const loadHistory = useCallback(async () => {
    try {
      const res  = await fetch('/api/history')
      const data = await res.json()
      if (Array.isArray(data)) setHistory(data)
    } catch (_) { /* MongoDB is optional — silently skip */ }
  }, [])

  useEffect(() => { loadHistory() }, [loadHistory])

  const handleSearch = async (companyName) => {
    setPhase('loading')
    setSteps([])
    setResult(null)
    setErrorMsg(null)
    setActiveTab('thesis')

    try {
      const response = await fetch('/api/research', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ companyName }),
      })

      if (!response.ok) {
        const err = await response.json()
        throw new Error(err.error || `Server error ${response.status}`)
      }

      // Stream SSE events from the backend
      const reader  = response.body.getReader()
      const decoder = new TextDecoder()
      let buffer    = ''

      while (true) {
        const { done, value } = await reader.read()
        if (done) break

        buffer += decoder.decode(value, { stream: true })
        const lines = buffer.split('\n')
        buffer      = lines.pop() // keep incomplete line in buffer

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue
          try {
            const event = JSON.parse(line.slice(6))
            if (event.type === 'progress') handleProgressEvent(event)
            if (event.type === 'result')   handleResultEvent(event)
            if (event.type === 'error')    handleErrorEvent(event)
          } catch (_) { /* ignore malformed SSE lines */ }
        }
      }
    } catch (err) {
      setErrorMsg(err.message)
      setPhase('error')
    }
  }

  const handleProgressEvent = ({ node, message }) => {
    setSteps(prev => {
      const exists = prev.find(s => s.node === node)
      if (exists) {
        return prev.map(s => s.node === node ? { ...s, message, status: 'done' } : s)
      }
      return [...prev, { node, label: NODE_LABELS[node] || node, message, status: 'active' }]
    })
  }

  const handleResultEvent = ({ result }) => {
    setResult(result)
    setPhase('result')
    setSteps(prev => prev.map(s => ({ ...s, status: 'done' })))
    loadHistory()
  }

  const handleErrorEvent = ({ message }) => {
    setErrorMsg(message)
    setPhase('error')
  }

  const tabs = [
    { id: 'thesis',     icon: '📋', label: 'Thesis'     },
    { id: 'financials', icon: '📊', label: 'Financials' },
    { id: 'sentiment',  icon: '📰', label: 'Sentiment'  },
    { id: 'signals',    icon: '🚦', label: 'Signals'    },
  ]

  return (
    <div style={{ minHeight: '100vh', position: 'relative' }}>
      {/* ── 3D Particle Background ── */}
      <ThreeBackground />

      {/* ── Layout ── */}
      <div style={{ position: 'relative', zIndex: 1, display: 'flex', minHeight: '100vh' }}>
        <HistorySidebar
          history={history}
          isOpen={sidebarOpen}
          onToggle={() => setSidebarOpen(o => !o)}
        />

        <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
          {/* ── Header ── */}
          <header style={{
            padding: '16px 28px',
            borderBottom: '1px solid rgba(255,255,255,0.05)',
            backdropFilter: 'blur(20px)',
            background: 'rgba(7,7,26,0.6)',
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
            position: 'sticky', top: 0, zIndex: 10,
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <button
                onClick={() => setSidebarOpen(o => !o)}
                style={{ background: 'none', border: 'none', color: 'var(--muted)', fontSize: 20, cursor: 'pointer', lineHeight: 1 }}
                aria-label="Toggle history sidebar"
              >
                ☰
              </button>
              <div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                  <span style={{ fontSize: 20 }}>🔬</span>
                  <h1 className="grad-text" style={{ fontSize: 18, fontWeight: 800, letterSpacing: '-0.02em' }}>
                    AI Investment Research Agent
                  </h1>
                </div>
                <p style={{ fontSize: 12, color: 'var(--dim)', marginTop: 2 }}>
                  InsideIIM × Altuni AI Labs
                </p>
              </div>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 12, color: 'var(--dim)' }}>
              <span className="anim-ping" style={{ width: 7, height: 7, borderRadius: '50%', background: 'var(--green)', display: 'inline-block' }} />
              Zero API Keys · Yahoo Finance
            </div>
          </header>

          {/* ── Main Content ── */}
          <main style={{ flex: 1, maxWidth: 900, width: '100%', margin: '0 auto', padding: '32px 20px', display: 'flex', flexDirection: 'column', gap: 20 }}>

            <SearchBar onSearch={handleSearch} disabled={phase === 'loading'} />

            {/* Agent progress tracker */}
            {(phase === 'loading' || (phase === 'result' && steps.length > 0)) && (
              <AgentProgress steps={steps} isLoading={phase === 'loading'} />
            )}

            {/* Error state */}
            {phase === 'error' && (
              <div className="glass anim-fade-up" style={{ padding: 20, border: '1px solid rgba(255,77,109,0.3)', background: 'rgba(255,77,109,0.07)' }}>
                <p style={{ color: 'var(--red)', fontWeight: 600 }}>⚠️ Research Failed</p>
                <p style={{ color: 'var(--muted)', fontSize: 14, marginTop: 6 }}>{errorMsg}</p>
              </div>
            )}

            {/* Results */}
            {phase === 'result' && result && (
              <div className="anim-fade-up" style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                <VerdictCard result={result} />

                {/* Tab bar */}
                <div className="glass" style={{ display: 'flex', gap: 4, padding: 6 }}>
                  {tabs.map(tab => (
                    <button
                      key={tab.id}
                      id={`tab-${tab.id}`}
                      onClick={() => setActiveTab(tab.id)}
                      style={{
                        flex: 1, padding: '10px 8px',
                        borderRadius: 10, border: 'none',
                        cursor: 'pointer', fontFamily: 'var(--font)',
                        fontSize: 13, fontWeight: 500,
                        transition: 'all 0.2s',
                        background: activeTab === tab.id ? 'rgba(79,142,247,0.15)' : 'transparent',
                        color:      activeTab === tab.id ? 'var(--blue)' : 'var(--dim)',
                        boxShadow:  activeTab === tab.id ? 'inset 0 0 0 1px rgba(79,142,247,0.3)' : 'none',
                      }}
                    >
                      {tab.icon} {tab.label}
                    </button>
                  ))}
                </div>

                {/* Tab content */}
                <div key={activeTab} className="anim-fade-up">
                  {activeTab === 'thesis'     && <ThesisPanel     result={result} />}
                  {activeTab === 'financials' && <FinancialsTable  metrics={result.financialMetrics} ticker={result.ticker} />}
                  {activeTab === 'sentiment'  && <SentimentPanel   articles={result.newsArticles} score={result.sentimentScore} />}
                  {activeTab === 'signals'    && <SignalsList       bullish={result.bullishSignals} risks={result.riskFlags} />}
                </div>
              </div>
            )}

            {/* Idle / welcome state */}
            {phase === 'idle' && (
              <div className="anim-fade-up" style={{ textAlign: 'center', paddingTop: 60, paddingBottom: 60 }}>
                <div className="anim-float" style={{ fontSize: 64, marginBottom: 20 }}>📈</div>
                <h2 style={{ fontSize: 26, fontWeight: 700, color: 'var(--text)', marginBottom: 10 }}>
                  Research Any Public Company
                </h2>
                <p style={{ color: 'var(--muted)', maxWidth: 420, margin: '0 auto', lineHeight: 1.7, fontSize: 15 }}>
                  Enter a company name. The agent fetches live financial data, scans real news,
                  and delivers a data-backed <strong style={{ color: 'var(--green)' }}>INVEST</strong> or <strong style={{ color: 'var(--red)' }}>PASS</strong> verdict instantly.
                </p>

                <div style={{ marginTop: 32, display: 'flex', flexWrap: 'wrap', justifyContent: 'center', gap: 10 }}>
                  {QUICK_PICKS.map(name => (
                    <button
                      key={name}
                      onClick={() => handleSearch(name)}
                      className="grad-border"
                      style={{
                        padding: '9px 18px', borderRadius: 999, border: '1px solid var(--border)',
                        background: 'rgba(255,255,255,0.03)', color: 'var(--muted)',
                        cursor: 'pointer', fontFamily: 'var(--font)', fontSize: 13,
                        transition: 'all 0.2s',
                      }}
                      onMouseEnter={e => { e.target.style.color = 'var(--text)'; e.target.style.borderColor = 'rgba(79,142,247,0.4)' }}
                      onMouseLeave={e => { e.target.style.color = 'var(--muted)'; e.target.style.borderColor = 'var(--border)' }}
                    >
                      {name}
                    </button>
                  ))}
                </div>

                {/* Feature badges */}
                <div style={{ marginTop: 48, display: 'flex', justifyContent: 'center', flexWrap: 'wrap', gap: 12 }}>
                  {['🏦 Live Financial Data', '📰 Real News RSS', '🤖 AI Scoring Engine', '⚡ Streaming Results'].map(f => (
                    <span key={f} className="glass" style={{ padding: '7px 14px', fontSize: 12, color: 'var(--muted)', borderRadius: 999 }}>
                      {f}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  )
}

import React, { useState } from 'react'

export default function SearchBar({ onSearch, disabled }) {
  const [value, setValue] = useState('')

  const submit = (e) => {
    e.preventDefault()
    if (value.trim() && !disabled) onSearch(value.trim())
  }

  return (
    <form onSubmit={submit}>
      <div style={{ position: 'relative' }}>
        {/* Animated glow ring */}
        <div style={{
          position: 'absolute', inset: -2, borderRadius: 18,
          background: 'linear-gradient(135deg, #4f8ef7, #8b5cf6, #4f8ef7)',
          backgroundSize: '200% 200%',
          animation: disabled ? 'gradShift 1.5s ease infinite' : 'none',
          opacity: disabled ? 0.6 : 0,
          transition: 'opacity 0.3s',
          filter: 'blur(6px)',
        }} />

        <div className="glass" style={{
          position: 'relative', display: 'flex', alignItems: 'center',
          borderRadius: 16, overflow: 'hidden', padding: '6px 6px 6px 20px',
        }}>
          <span style={{ fontSize: 18, opacity: 0.35, flexShrink: 0 }}>🔍</span>

          <input
            id="company-search-input"
            type="text"
            value={value}
            onChange={e => setValue(e.target.value)}
            placeholder="Enter company name — e.g. Apple Inc., Reliance Industries, Tesla..."
            disabled={disabled}
            autoComplete="off"
            style={{
              flex: 1, background: 'transparent', border: 'none', outline: 'none',
              padding: '16px 14px', color: 'var(--text)', fontSize: 15,
              fontFamily: 'var(--font)', opacity: disabled ? 0.5 : 1,
            }}
          />

          <button
            id="search-submit-btn"
            type="submit"
            disabled={disabled || !value.trim()}
            style={{
              padding: '14px 26px', borderRadius: 12, border: 'none',
              background: disabled || !value.trim()
                ? 'rgba(79,142,247,0.2)'
                : 'linear-gradient(135deg, #4f8ef7, #8b5cf6)',
              color: 'white', fontWeight: 600, fontSize: 14,
              cursor: disabled || !value.trim() ? 'not-allowed' : 'pointer',
              display: 'flex', alignItems: 'center', gap: 8,
              whiteSpace: 'nowrap', fontFamily: 'var(--font)',
              transition: 'all 0.2s', flexShrink: 0,
            }}
          >
            {disabled
              ? <><svg className="anim-spin" style={{ width: 16, height: 16 }} viewBox="0 0 24 24" fill="none"><circle style={{ opacity: 0.25 }} cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/><path style={{ opacity: 0.75 }} fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/></svg> Analyzing...</>
              : 'Analyze →'
            }
          </button>
        </div>
      </div>
    </form>
  )
}

import React from 'react'

const STEP_ORDER = [
  { key: 'validating',      icon: '🔍', label: 'Input Validation'      },
  { key: 'ticker_resolved', icon: '🏷️',  label: 'Ticker Resolved'       },
  { key: 'researching',     icon: '📡', label: 'Parallel Data Fetch'    },
