export default function FinancialsTable({ metrics, ticker }) {
  if (!metrics) {
    return (
      <div className="glass" style={{ padding: 48, textAlign: 'center' }}>
        <div style={{ fontSize: 40, marginBottom: 12 }}>📊</div>
        <p style={{ color: 'var(--muted)', fontSize: 14 }}>No financial data available — company may not be publicly listed.</p>
      </div>
    )
  }

  const upside = metrics.targetMeanPrice && metrics.currentPrice
    ? ((metrics.targetMeanPrice - metrics.currentPrice) / metrics.currentPrice * 100)
    : null

  return (
    <div className="glass" style={{ overflow: 'hidden' }}>
      {/* Header */}
      <div style={{ padding: '16px 24px', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--dim)', letterSpacing: '0.1em', textTransform: 'uppercase' }}>
          Financial Metrics
        </span>
        {ticker && <span className="mono" style={{ color: 'var(--blue)', fontSize: 13 }}>{ticker}</span>}
      </div>

      {/* Analyst upside / downside banner */}
      {upside != null && (
        <div style={{
          padding: '10px 24px', fontSize: 13,
          color:       upside > 0 ? 'var(--green)' : 'var(--red)',
          background:  upside > 0 ? 'rgba(16,217,138,0.06)' : 'rgba(255,77,109,0.06)',
          borderBottom: '1px solid var(--border)',
        }}>
          Analyst consensus target: {upside > 0 ? '+' : ''}{upside.toFixed(1)}% to ${metrics.targetMeanPrice.toFixed(2)}
        </div>
      )}

      {/* Metric rows */}
      {METRICS.map(({ key, label, fmt, signed }) => {
        const val = metrics[key]
        if (val == null) return null

        const valueColor = signed && val > 0 ? 'var(--green)'
                         : signed && val < 0 ? 'var(--red)'
                         : 'var(--text)'

        return (
          <div
            key={key}
            style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              padding: '12px 24px', borderBottom: '1px solid rgba(255,255,255,0.03)',
              transition: 'background 0.15s',
            }}
            onMouseEnter={e => e.currentTarget.style.background = 'rgba(255,255,255,0.02)'}
            onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
          >
            <span style={{ fontSize: 13, color: 'var(--muted)' }}>{label}</span>
            <span className="mono" style={{ fontSize: 13, fontWeight: 600, color: valueColor }}>{fmt(val)}</span>
          </div>
        )
      })}

      <div style={{ padding: '10px 24px', fontSize: 11, color: 'rgba(255,255,255,0.18)' }}>
        Source: Yahoo Finance · Not financial advice
      </div>
    </div>
  )
}

import React from 'react'

const LABEL_COLOR = {
  BULLISH:  { color: '#10d98a', bg: 'rgba(16,217,138,0.12)',  border: 'rgba(16,217,138,0.3)'  },
  POSITIVE: { color: '#10d98a', bg: 'rgba(16,217,138,0.12)',  border: 'rgba(16,217,138,0.3)'  },
  BEARISH:  { color: '#ff4d6d', bg: 'rgba(255,77,109,0.12)',  border: 'rgba(255,77,109,0.3)'  },
  NEGATIVE: { color: '#ff4d6d', bg: 'rgba(255,77,109,0.12)',  border: 'rgba(255,77,109,0.3)'  },
  NEUTRAL:  { color: '#f59e0b', bg: 'rgba(245,158,11,0.12)',  border: 'rgba(245,158,11,0.3)'  },
}

function SentimentGauge({ score }) {
  const label   = score >= 65 ? 'BULLISH' : score >= 45 ? 'NEUTRAL' : 'BEARISH'
  const col     = LABEL_COLOR[label]
  const R       = 38
  const circum  = 2 * Math.PI * R
  const dash    = (score / 100) * circum

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
      {/* SVG dial */}
      <div style={{ position: 'relative', width: 96, height: 96, flexShrink: 0 }}>
        <svg viewBox="0 0 100 100" style={{ width: '100%', height: '100%', transform: 'rotate(-90deg)' }}>
          <circle cx="50" cy="50" r={R} fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="10" />
          <circle
            cx="50" cy="50" r={R} fill="none"
            stroke={col.color} strokeWidth="10"
            strokeLinecap="round"
            strokeDasharray={`${dash} ${circum}`}
            style={{ transition: 'stroke-dasharray 1.2s cubic-bezier(0.22,1,0.36,1)' }}
          />
        </svg>
        <div style={{
          position: 'absolute', inset: 0,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <span className="mono" style={{ fontSize: 18, fontWeight: 700, color: col.color }}>
            {score?.toFixed(0) ?? '--'}
          </span>
        </div>
      </div>

      <div>
        <div style={{ fontSize: 24, fontWeight: 800, color: col.color }}>{label}</div>
        <div style={{ fontSize: 13, color: 'var(--muted)', marginTop: 4 }}>Overall sentiment score</div>
      </div>
    </div>
  )
}

export default function SentimentPanel({ articles = [], score }) {
